-- ===========================================================================
-- Haikesi_Relics.sql — 棱彩海克斯符文数据表
-- Name/Description/Flavor 存 LOC key，Lua 通过 Locale.Lookup 翻译
-- 共 95 个棱彩符文
-- ===========================================================================

CREATE TABLE IF NOT EXISTS Haikesi_Relics (
    RelicType   TEXT NOT NULL PRIMARY KEY,
    Name        TEXT NOT NULL,
    Description TEXT,
    Flavor      TEXT,
    Icon        TEXT,
    Rarity      TEXT DEFAULT 'PRISMATIC',
    IsActive    INTEGER DEFAULT 0,
    IsRepeatable INTEGER DEFAULT 1,
    SelectionOnly INTEGER DEFAULT 0,
    Weight      INTEGER DEFAULT 100,
    MinTurn     INTEGER DEFAULT NULL,
    MaxTurn     INTEGER DEFAULT NULL
);

